70: // ValidateNetworkPolicyPort validates a NetworkPolicyPort
71: func ValidateNetworkPolicyPort(port *networking.NetworkPolicyPort, portPath *field.Path) field.ErrorList {
72: 	allErrs := field.ErrorList{}
73: 	if port.Protocol != nil && *port.Protocol != api.ProtocolTCP && *port.Protocol != api.ProtocolUDP && *port.Protocol != api.ProtocolSCTP {
74: 		allErrs = append(allErrs, field.NotSupported(portPath.Child("protocol"), *port.Protocol, []string{string(api.ProtocolTCP), string(api.ProtocolUDP), string(api.ProtocolSCTP)}))
75: 	}
76: 	if port.Port != nil {
77: 		if port.Port.Type == intstr.Int {
78: 			for _, msg := range validation.IsValidPortNum(int(port.Port.IntVal)) {
79: 				allErrs = append(allErrs, field.Invalid(portPath.Child("port"), port.Port.IntVal, msg))
80: 			}
81: 			if port.EndPort != nil {
82: 				if *port.EndPort < port.Port.IntVal {
83: 					allErrs = append(allErrs, field.Invalid(portPath.Child("endPort"), port.Port.IntVal, "must be greater than or equal to `port`"))
84: 				}
85: 				for _, msg := range validation.IsValidPortNum(int(*port.EndPort)) {
86: 					allErrs = append(allErrs, field.Invalid(portPath.Child("endPort"), *port.EndPort, msg))
87: 				}
88: 			}
89: 		} else {
90: 			if port.EndPort != nil {
91: 				allErrs = append(allErrs, field.Invalid(portPath.Child("endPort"), *port.EndPort, "may not be specified when `port` is non-numeric"))
92: 			}
93: 			for _, msg := range validation.IsValidPortName(port.Port.StrVal) {
94: 				allErrs = append(allErrs, field.Invalid(portPath.Child("port"), port.Port.StrVal, msg))
95: 			}
96: 		}
97: 	} else {
98: 		if port.EndPort != nil {
99: 			allErrs = append(allErrs, field.Invalid(portPath.Child("endPort"), *port.EndPort, "may not be specified when `port` is not specified"))
100: 		}
101: 	}
102: 
103: 	return allErrs
104: }
