106: // ValidateNetworkPolicyPeer validates a NetworkPolicyPeer
107: func ValidateNetworkPolicyPeer(peer *networking.NetworkPolicyPeer, opts NetworkPolicyValidationOptions, peerPath *field.Path) field.ErrorList {
108: 	allErrs := field.ErrorList{}
109: 	numPeers := 0
110: 	labelSelectorValidationOpts := unversionedvalidation.LabelSelectorValidationOptions{
111: 		AllowInvalidLabelValueInSelector: opts.AllowInvalidLabelValueInSelector,
112: 	}
113: 
114: 	if peer.PodSelector != nil {
115: 		numPeers++
116: 		allErrs = append(allErrs, unversionedvalidation.ValidateLabelSelector(peer.PodSelector, labelSelectorValidationOpts, peerPath.Child("podSelector"))...)
117: 	}
118: 	if peer.NamespaceSelector != nil {
119: 		numPeers++
120: 		allErrs = append(allErrs, unversionedvalidation.ValidateLabelSelector(peer.NamespaceSelector, labelSelectorValidationOpts, peerPath.Child("namespaceSelector"))...)
121: 	}
122: 	if peer.IPBlock != nil {
123: 		numPeers++
124: 		allErrs = append(allErrs, ValidateIPBlock(peer.IPBlock, peerPath.Child("ipBlock"), opts)...)
125: 	}
126: 
127: 	if numPeers == 0 {
128: 		allErrs = append(allErrs, field.Required(peerPath, "must specify a peer"))
129: 	} else if numPeers > 1 && peer.IPBlock != nil {
130: 		allErrs = append(allErrs, field.Forbidden(peerPath, "may not specify both ipBlock and another peer"))
131: 	}
132: 
133: 	return allErrs
134: }
