136: // ValidateNetworkPolicySpec tests if required fields in the networkpolicy spec are set.
137: func ValidateNetworkPolicySpec(spec *networking.NetworkPolicySpec, opts NetworkPolicyValidationOptions, fldPath *field.Path) field.ErrorList {
138: 	allErrs := field.ErrorList{}
139: 	labelSelectorValidationOpts := unversionedvalidation.LabelSelectorValidationOptions{
140: 		AllowInvalidLabelValueInSelector: opts.AllowInvalidLabelValueInSelector,
141: 	}
142: 	allErrs = append(allErrs, unversionedvalidation.ValidateLabelSelector(
143: 		&spec.PodSelector,
144: 		labelSelectorValidationOpts,
145: 		fldPath.Child("podSelector"),
146: 	)...)
147: 
148: 	// Validate ingress rules.
149: 	for i, ingress := range spec.Ingress {
150: 		ingressPath := fldPath.Child("ingress").Index(i)
151: 		for i, port := range ingress.Ports {
152: 			portPath := ingressPath.Child("ports").Index(i)
153: 			allErrs = append(allErrs, ValidateNetworkPolicyPort(&port, portPath)...)
154: 		}
155: 		for i, from := range ingress.From {
156: 			fromPath := ingressPath.Child("from").Index(i)
157: 			allErrs = append(allErrs, ValidateNetworkPolicyPeer(&from, opts, fromPath)...)
158: 		}
159: 	}
160: 	// Validate egress rules
161: 	for i, egress := range spec.Egress {
162: 		egressPath := fldPath.Child("egress").Index(i)
163: 		for i, port := range egress.Ports {
164: 			portPath := egressPath.Child("ports").Index(i)
165: 			allErrs = append(allErrs, ValidateNetworkPolicyPort(&port, portPath)...)
166: 		}
167: 		for i, to := range egress.To {
168: 			toPath := egressPath.Child("to").Index(i)
169: 			allErrs = append(allErrs, ValidateNetworkPolicyPeer(&to, opts, toPath)...)
170: 		}
171: 	}
172: 	// Validate PolicyTypes
173: 	allowed := sets.NewString(string(networking.PolicyTypeIngress), string(networking.PolicyTypeEgress))
174: 	if len(spec.PolicyTypes) > len(allowed) {
175: 		allErrs = append(allErrs, field.Invalid(fldPath.Child("policyTypes"), &spec.PolicyTypes, "may not specify more than two policyTypes"))
176: 		return allErrs
177: 	}
178: 	for i, pType := range spec.PolicyTypes {
179: 		policyPath := fldPath.Child("policyTypes").Index(i)
180: 		if !allowed.Has(string(pType)) {
181: 			allErrs = append(allErrs, field.NotSupported(policyPath, pType, []string{string(networking.PolicyTypeIngress), string(networking.PolicyTypeEgress)}))
182: 		}
183: 	}
184: 	return allErrs
185: }
