210: // ValidateNetworkPolicyUpdate tests if an update to a NetworkPolicy is valid.
211: func ValidateNetworkPolicyUpdate(update, old *networking.NetworkPolicy, opts NetworkPolicyValidationOptions) field.ErrorList {
212: 	// Record all existing CIDRs in the policy; see ValidateIPBlock.
213: 	var existingCIDRs []string
214: 	for _, ingress := range old.Spec.Ingress {
215: 		for _, peer := range ingress.From {
216: 			if peer.IPBlock != nil {
217: 				existingCIDRs = append(existingCIDRs, peer.IPBlock.CIDR)
218: 				existingCIDRs = append(existingCIDRs, peer.IPBlock.Except...)
219: 			}
220: 		}
221: 	}
222: 	for _, egress := range old.Spec.Egress {
223: 		for _, peer := range egress.To {
224: 			if peer.IPBlock != nil {
225: 				existingCIDRs = append(existingCIDRs, peer.IPBlock.CIDR)
226: 				existingCIDRs = append(existingCIDRs, peer.IPBlock.Except...)
227: 			}
228: 		}
229: 	}
230: 	opts.AllowCIDRsEvenIfInvalid = existingCIDRs
231: 
232: 	allErrs := field.ErrorList{}
233: 	allErrs = append(allErrs, apivalidation.ValidateObjectMetaUpdate(&update.ObjectMeta, &old.ObjectMeta, field.NewPath("metadata"))...)
234: 	allErrs = append(allErrs, ValidateNetworkPolicySpec(&update.Spec, opts, field.NewPath("spec"))...)
235: 	return allErrs
236: }
