238: // ValidateIPBlock validates a cidr and the except fields of an IPBlock NetworkPolicyPeer.
239: //
240: // If a pre-existing CIDR is invalid/insecure, but it is not being changed by this update,
241: // then we have to continue allowing it. But since the user may have changed the policy in
242: // arbitrary ways (adding/removing rules, adding/removing peers, adding/removing
243: // ipBlock.except values, etc), we can't reliably determine whether a CIDR value we see
244: // here is a new value or a pre-existing one. So we just allow any CIDR value that
245: // appeared in the old NetworkPolicy to be used here without revalidation.
246: func ValidateIPBlock(ipb *networking.IPBlock, fldPath *field.Path, opts NetworkPolicyValidationOptions) field.ErrorList {
247: 	allErrs := field.ErrorList{}
248: 	if ipb.CIDR == "" {
249: 		allErrs = append(allErrs, field.Required(fldPath.Child("cidr"), "").MarkCoveredByDeclarative())
250: 		return allErrs
251: 	}
252: 	allErrs = append(allErrs, apivalidation.IsValidCIDRForLegacyField(fldPath.Child("cidr"), ipb.CIDR, opts.AllowCIDRsEvenIfInvalid)...)
253: 	_, cidrIPNet, err := netutils.ParseCIDRSloppy(ipb.CIDR)
254: 	if err != nil {
255: 		// Implies validation would have failed so we already added errors for it.
256: 		return allErrs
257: 	}
258: 
259: 	for i, exceptCIDRStr := range ipb.Except {
260: 		exceptPath := fldPath.Child("except").Index(i)
261: 		allErrs = append(allErrs, apivalidation.IsValidCIDRForLegacyField(exceptPath, exceptCIDRStr, opts.AllowCIDRsEvenIfInvalid)...)
262: 		_, exceptCIDR, err := netutils.ParseCIDRSloppy(exceptCIDRStr)
263: 		if err != nil {
264: 			// Implies validation would have failed so we already added errors for it.
265: 			continue
266: 		}
267: 
268: 		cidrMaskLen, _ := cidrIPNet.Mask.Size()
269: 		exceptMaskLen, _ := exceptCIDR.Mask.Size()
270: 		if !cidrIPNet.Contains(exceptCIDR.IP) || cidrMaskLen >= exceptMaskLen {
271: 			allErrs = append(allErrs, field.Invalid(exceptPath, exceptCIDRStr, "must be a strict subset of `cidr`"))
272: 		}
273: 	}
274: 	return allErrs
275: }
