330: func validateIngressTLS(spec *networking.IngressSpec, fldPath *field.Path, opts IngressValidationOptions) field.ErrorList {
331: 	allErrs := field.ErrorList{}
332: 	// TODO: Perform a more thorough validation of spec.TLS.Hosts that takes
333: 	// the wildcard spec from RFC 6125 into account.
334: 	for tlsIndex, itls := range spec.TLS {
335: 		for i, host := range itls.Hosts {
336: 			if strings.Contains(host, "*") {
337: 				for _, msg := range validation.IsWildcardDNS1123Subdomain(host) {
338: 					allErrs = append(allErrs, field.Invalid(fldPath.Index(tlsIndex).Child("hosts").Index(i), host, msg))
339: 				}
340: 				continue
341: 			}
342: 			for _, msg := range validation.IsDNS1123Subdomain(host) {
343: 				allErrs = append(allErrs, field.Invalid(fldPath.Index(tlsIndex).Child("hosts").Index(i), host, msg))
344: 			}
345: 		}
346: 
347: 		if !opts.AllowInvalidSecretName {
348: 			for _, msg := range validateTLSSecretName(itls.SecretName) {
349: 				allErrs = append(allErrs, field.Invalid(fldPath.Index(tlsIndex).Child("secretName"), itls.SecretName, msg))
350: 			}
351: 		}
352: 	}
353: 
354: 	return allErrs
355: }
